#include<bits/stdc++.h>
using namespace std;
map<long long, int>m;
stack<pair<int,int> > s;
long long cnt;
int main()
{
	int n;
	cin >> n;
	cnt = 0;
	for(int i = 0 ; i < n; i++){
		long long a;
		cin >> a;
		int num = 1;
		while(s.size() && a >= s.top().first){
			cnt += s.top().second;
			if(a == s.top().first) num += s.top().second;
			s.pop();
//			cout << cnt << endl;
		}
		if(!s.empty()) cnt ++;
		s.push({a, num});
	}
	cout << cnt;
}
